INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Écho', 'Échographie Abdominale', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen échographique de l''abdomen réalisé par voie transpariétale à l''aide d''une sonde convexe multifréquence. Le patient est examiné en décubitus dorsal, avec des variations de position si nécessaire. Une préparation à jeun a été observée pour optimiser la visualisation des structures abdominales.</p><p><strong>RÉSULTATS :</strong></p><p>Le foie est de taille normale, avec une échostructure homogène et des contours réguliers. Les veines hépatiques et le système porte présentent un aspect et des flux normaux.</p><p>La vésicule biliaire est de forme et de taille normales, à contenu anéchogène et à paroi fine et régulière. Elle est alithiasique et sans sludge.</p><p>Les voies biliaires intra-hépatiques ne sont pas dilatées. La voie biliaire principale est de calibre normal et libre sur tout son trajet.</p><p>Le pancréas est de taille normale, avec une échostructure homogène et des contours réguliers. Le canal pancréatique principal (Wirsung) est non dilaté.</p><p>La rate est de taille et de morphologie normales, avec une échostructure fine et homogène.</p><p>Les deux reins sont de taille, forme et échostructure normales, avec une bonne différenciation cortico-médullaire. Il n''y a pas de dilatation des cavités pyélocalicielles ni de calculs. Les uretères proximaux sont d''aspect normal.</p><p>L''aorte abdominale est de calibre normal, sans signe d''anévrisme, de sténose ou de dissection, avec des parois régulières. La veine cave inférieure est perméable et de calibre normal.</p><p>La vessie est de remplissage adéquat, à contenu anéchogène et à parois fines et régulières.</p><p>Absence d''épanchement liquidien intra-abdominal.</p><p><strong>CONCLUSION :</strong></p><p>Examen échographique abdominal sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Écho', 'Échographie Thyroïdienne', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Échographie de la région cervicale antérieure centrée sur la glande thyroïde, réalisée à l''aide d''une sonde linéaire haute fréquence. Une étude en mode B et Doppler couleur a été effectuée pour évaluer la morphologie, l''échostructure et la vascularisation de la glande, ainsi que les structures cervicales adjacentes.</p><p><strong>RÉSULTATS :</strong></p><p>La glande thyroïde est de taille normale, avec un volume global dans les limites physiologiques (10-28 cm³).</p><p>Les lobes thyroïdiens droit et gauche sont de forme piriforme, de dimensions normales (longueur 4-6 cm, profondeur <2 cm), et présentent des contours réguliers.</p><p>L''isthme thyroïdien est de fine épaisseur, mesurant moins de 5 mm.</p><p>Le parenchyme thyroïdien est homogène et hyperéchogène par rapport aux muscles adjacents, sans anomalie focale ni diffuse.</p><p>La vascularisation intra-parenchymateuse est normale au Doppler couleur, sans signe d''hypervascularisation.</p><p>Le lobe pyramidal, s''il est présent, est de taille normale et d''aspect non pathologique, correspondant à une variante anatomique.</p><p>Les glandes parathyroïdes ne sont pas visualisées, ce qui est l''aspect normal en échographie.</p><p>Les structures cervicales adjacentes, incluant la trachée et les axes jugulo-carotidiens, sont de calibre normal et sans compression.</p><p>Il n''y a pas d''adénopathie cervicale pathologique détectée dans les chaînes ganglionnaires explorées. Les ganglions d''aspect normal ne sont pas signalés.</p><p>Aucun tissu thyroïdien ectopique n''est visible.</p><p><strong>CONCLUSION :</strong></p><p>Examen échographique de la thyroïde sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Écho', 'Échographie Pelvienne Femme', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen réalisé par voies sus-pubienne et endovaginale selon les cas, complété par une exploration en mode Doppler couleur et pulsé si nécessaire. La vessie est correctement remplie, permettant une visualisation optimale des structures pelviennes.</p><p><strong>RÉSULTATS :</strong></p><p>Utérus : De taille et morphologie normales pour l''âge et la parité de la patiente. Le myomètre est d''échostructure homogène, sans masse ou lésion focale identifiable.</p><p>Endomètre : L''épaisseur et l''échostructure de l''endomètre sont en adéquation avec la phase du cycle menstruel/statut hormonal de la patiente. La ligne cavitaire est fine et régulière.</p><p>Ovaires : Les deux ovaires sont visualisés, de taille et d''échostructure normales. Le stroma ovarien est homogène. Présence de follicules physiologiques de taille et nombre normaux, sans kyste pathologique.</p><p>Vessie : La vessie est bien distendue, à parois fines et régulières. Son contenu est anéchogène, sans formation endoluminale ni résidu post-mictionnel significatif.</p><p>Cul-de-sac de Douglas : Absence d''épanchement liquidien libre significatif.</p><p>Trompes de Fallope : Les trompes de Fallope ne sont pas visualisées, ce qui est l''aspect normal en l''absence de pathologie.</p><p><strong>CONCLUSION :</strong></p><p>Examen échographique pelvien féminin sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Écho', 'Échographie Rénale et Vésicale', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Examen échographique des régions rénales et vésicales réalisé selon les coupes standard et avec application de gel acoustique. Le Doppler couleur a été utilisé pour l''évaluation vasculaire des reins.</p><p><strong>RÉSULTATS :</strong></p><p><strong>Reins :</strong></p><p>Les deux reins sont de taille, de forme et de position normales. Le rein droit mesure X mm et le rein gauche mesure Y mm (longueur normale chez l''adulte : 9 à 12 cm).</p><p>Le parenchyme rénal présente une échogénicité normale et homogène, avec une bonne différenciation cortico-médullaire.</p><p>Le système collecteur (bassinet et calices) n''est pas dilaté, sans signe d''hydronéphrose.</p><p>La vascularisation rénale bilatérale évaluée par Doppler couleur montre des flux sanguins normaux, sans signe de sténose des artères rénales ou d''anomalie intraparenchymateuse.</p><p>Aucune masse, kyste simple ou complexe, ou calcul n''est visualisé dans les reins.</p><p>Les contours rénaux sont réguliers et la capsule est intègre.</p><p><strong>Vessie :</strong></p><p>La vessie est bien distendue avec un contenu anéchogène et homogène, sans échos intraluminaux.</p><p>La paroi vésicale est fine et régulière, sans épaississement focal ni diffus.</p><p>Aucune masse, polype ou calcul n''est détecté dans la lumière vésicale ou adhérant à la paroi.</p><p>Les jets urétéraux sont visibles et symétriques.</p><p>Le volume résiduel post-mictionnel (si évalué) est normal.</p><p><strong>CONCLUSION :</strong></p><p>Examen échographique rénal et vésical normal.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Écho', 'Écho-Doppler veineux des membres inférieurs', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen réalisé en mode B et Doppler couleur/pulsé, avec manœuvres de compression et de Valsalva si nécessaire, et tests d''augmentation distale.</p><p><strong>RÉSULTATS :</strong></p><p><strong>Système veineux profond :</strong></p><p>La veine fémorale commune, la veine fémorale (superficielle), la veine fémorale profonde et la veine poplitée sont toutes entièrement compressibles, avec un calibre et une échogénicité pariétale normaux, sans évidence de matériel intraluminal ni de signes de thrombose.</p><p>Les veines tibiales antérieures, tibiales postérieures, fibulaires (péronières) et jumelles (gastrocnémiennes) sont également entièrement compressibles sur l''ensemble de leur trajet visualisé, anéchogènes et de calibre normal, sans thrombus.</p><p>Le flux Doppler au sein du réseau veineux profond est spontané, phasique avec la respiration (modulé par la respiration) et unidirectionnel, sans reflux significatif au repos ni lors des manœuvres dynamiques.</p><p>Les valves veineuses sont fonctionnelles et compétentes, assurant un flux centripète.</p><p><strong>Système veineux superficiel :</strong></p><p>La grande veine saphène (interne) et la petite veine saphène (externe) sont de calibre normal, entièrement compressibles et sans thrombus.</p><p>Les jonctions saphéno-fémorale et saphéno-poplitée sont perméables, sans signe de reflux pathologique.</p><p>Le flux Doppler est physiologique, sans reflux significatif détecté au sein des axes saphéniens et de leurs principales tributaires.</p><p>Les veines perforantes visualisées sont perméables et continentales, assurant un drainage adéquat du système superficiel vers le système profond.</p><p>Aucune anomalie des parois veineuses, ectasie, ou varice n''est mise en évidence.</p><p>Absence d''anomalie périfasciale ou perivasculaire.</p><p><strong>CONCLUSION :</strong></p><p>Écho-Doppler veineux des membres inférieurs bilatéralement normal, sans signe de thrombose veineuse profonde ou superficielle ni d''insuffisance veineuse significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'IRM', 'IRM Cérébrale', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen réalisé selon les séquences standard en pondération T1, T2, FLAIR, T2* et de diffusion, dans les plans axial, sagittal et coronal. Des séquences complémentaires ont été acquises selon le protocole de routine.</p><p><strong>RÉSULTATS :</strong></p><p>La différenciation substance grise / substance blanche est physiologique et harmonieuse sur toutes les séquences.</p><p>Le système ventriculaire (ventricules latéraux, troisième et quatrième ventricules) est de taille et de configuration normales, symétrique, sans dilatation ni compression.</p><p>Les citernes de la base et les espaces sous-arachnoïdiens sont libres et de largeur normale, avec des sillons corticaux d''aspect habituel pour l''âge.</p><p>Les structures de la ligne médiane sont en place, sans décalage.</p><p>Le tronc cérébral (mésencéphale, pont et bulbe rachidien) présente une morphologie et un signal normaux.</p><p>Le cervelet et les hémisphères cérébelleux ont un aspect normal, sans anomalie de signal ni de volume.</p><p>Les noyaux gris centraux (thalamus, noyaux lenticulaires, noyaux caudés) ont un signal et une morphologie normaux.</p><p>Le corps calleux est d''épaisseur et de signal normaux.</p><p>La région sellaire et l''hypophyse, ainsi que la glande pinéale, sont d''aspect habituel.</p><p>La vascularisation cérébrale principale est sans anomalie notable de signal ou de calibre sur les séquences de flux (si réalisées).</p><p>Les orbites, les sinus paranasaux et les cellules mastoïdiennes sont clairs.</p><p>Les structures osseuses de la voûte et de la base du crâne sont sans anomalie détectable.</p><p><strong>CONCLUSION :</strong></p><p>IRM cérébrale sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'IRM', 'IRM du Genou', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen réalisé en coupes multiplanaires (axiales, coronales et sagittales) en séquences pondérées en T1, T2 avec suppression de graisse (FAT SAT ou SPIR) et en densité de protons (DP FAT SAT), selon les protocoles standards de l''IRM du genou.</p><p><strong>RÉSULTATS :</strong></p><p>Les structures osseuses (fémur distal, tibia proximal, patella et fibula proximale) présentent des contours réguliers et un signal médullaire homogène, sans anomalie significative de signal, fracture ou œdème.</p><p>Les cartilages articulaires fémoro-tibial et fémoro-patellaire sont d''épaisseur conservée et de signal homogène, sans irrégularité ni perte de substance significative.</p><p>Le ménisque interne et le ménisque externe sont de morphologie et de signal normaux, uniformément hypointenses sur toutes les séquences, sans signe de fissure ni de dégénérescence significative. Le ménisque interne a une forme en "C ouvert" et le ménisque externe est plus fermé, en "O", avec une section triangulaire en coupe sagittale.</p><p>Le ligament croisé antérieur (LCA) est intact, tendu et de signal hypointense habituel, avec une orientation normale des faisceaux.</p><p>Le ligament croisé postérieur (LCP) est intact, continu et de signal hypointense, de calibre normal.</p><p>Les ligaments collatéraux médial et latéral sont continus, d''épaisseur et de signal normaux, sans signe d''étirement ou de rupture.</p><p>Le tendon patellaire (rotulien) et le tendon quadricipital sont intacts, de signal hypointense et d''épaisseur normale.</p><p>Les autres tendons périarticulaires (notamment les ischio-jambiers, les gastrocnémiens et le poplité) sont sans anomalie d''insertion, de signal ou de morphologie.</p><p>La graisse de Hoffa (corps adipeux infrapatellaire) est de signal homogène, sans processus expansif ni signe inflammatoire.</p><p>Il n''y a pas d''épanchement intra-articulaire significatif ni de distension des bourses séreuses périarticulaires.</p><p>Les structures musculaires visibles dans le champ d''exploration sont de morphologie et de signal normaux.</p><p><strong>CONCLUSION :</strong></p><p>Examen IRM du genou de morphologie et de signal normaux.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'IRM', 'IRM du Rachis Lombaire', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>IRM du rachis lombaire réalisée selon un protocole standard comprenant des séquences sagittales T1, T2 et STIR, ainsi que des coupes axiales T2 centrées sur les espaces discaux.</p><p><strong>RÉSULTATS :</strong></p><p>L''alignement global du rachis lombaire est physiologique, sans anomalie de la courbure lordotique.</p><p>Les corps vertébraux présentent une morphologie et un signal médullaire normaux pour l''âge, sans lésion focale ni tassement. Les plateaux vertébraux sont réguliers, sans remaniements significatifs de signal (type Modic).</p><p>Les disques intervertébraux lombaires (de L1-L2 à L5-S1) sont de hauteur et de signal hydrique conservés, hyperintenses en T2, témoignant d''une hydratation normale du nucleus pulposus et d''un annulus fibrosus intact. Il n''y a pas de protrusion, hernie discale, ni fissure annulaire visible.</p><p>Le canal rachidien lombaire est de calibre normal, sans sténose centrale significative. La moelle épinière est libre, entourée de liquide céphalo-rachidien, et les racines de la queue de cheval sont bien individualisées et sans signes de compression.</p><p>Le cône médullaire est en position normale, terminant à hauteur de L1-L2, et les racines de la queue de cheval sont fines et flottent librement dans le sac dural.</p><p>Les foramens neuraux (trous de conjugaison) sont dégagés de chaque côté à tous les étages lombaires, permettant le libre passage des racines nerveuses correspondantes.</p><p>Les articulations interapophysaires postérieures (facettes articulaires) sont d''aspect normal, sans arthrose significative, hypertrophie capsulaire ou épanchement.</p><p>Les ligaments rachidiens (notamment les ligaments jaunes et le ligament longitudinal postérieur) sont de calibre et de signal normaux, sans signe d''hypertrophie ou d''inflammation.</p><p>Les muscles paravertébraux sont de volume et de signal normaux, sans atrophie significative ni infiltration graisseuse pathologique.</p><p><strong>CONCLUSION :</strong></p><p>IRM du rachis lombaire sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'IRM', 'Épaule', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>IRM de l''épaule droite/gauche réalisée selon un protocole standard comprenant des séquences en pondération T1, T2 avec suppression de graisse (Fat Sat) et Densité de Proton avec suppression de graisse (PD Fat Sat) dans les plans axial, coronal et sagittal.</p><p><strong>RÉSULTATS :</strong></p><p>Les structures osseuses, notamment la tête humérale, la glène, l''acromion, la clavicule et le processus coracoïde, présentent un alignement et une morphologie normaux. Le signal de la moelle osseuse est homogène et sans anomalie focale.</p><p>L''articulation gléno-humérale est bien centrée. Le cartilage articulaire qui recouvre la tête humérale et la glène est d''épaisseur conservée et de signal homogène.</p><p>Les tendons de la coiffe des rotateurs (supra-épineux, infra-épineux, subscapulaire et petit rond) sont de calibre, de morphologie et de signal normaux, sans signe de rupture ou de tendinopathie. Leurs insertions humérales sont intactes.</p><p>Le tendon de la longue portion du biceps est en place dans la gouttière bicipitale, de calibre et de signal normaux, sans signe de ténosynovite ou de rupture.</p><p>Le bourrelet glénoïdien est bien conformé, de signal homogène, fermement attaché à la glène sur toute sa circonférence, sans signe de déchirure.</p><p>Les ligaments gléno-huméraux (supérieur, moyen et inférieur) sont bien individualisés, de calibre et de signal normaux, sans signe de distension ou de rupture.</p><p>L''articulation acromio-claviculaire est d''aspect normal, sans signe d''arthropathie dégénérative significative ni d''œdème péri-articulaire.</p><p>La bourse sous-acromio-deltoïdienne est fine et sans épanchement notable.</p><p>Les autres muscles péri-articulaires (notamment deltoïde, grand pectoral, coraco-brachial) sont de taille normale et sans infiltration graisseuse anormale.</p><p>Il n''y a pas d''épanchement articulaire significatif ni de corps étranger intra-articulaire.</p><p>Les structures vasculaires et nerveuses visualisées sont sans particularité.</p><p><strong>CONCLUSION :</strong></p><p>IRM de l''épaule droite/gauche sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'TDM Thoracique', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Examen réalisé en tomodensitométrie multi-barrettes du thorax en acquisition volumique, sans et/ou avec injection intraveineuse de produit de contraste iodé (selon le protocole standard), avec reconstructions multiplanaires axiales, coronales et sagittales.</p><p><strong>RÉSULTATS :</strong></p><p>Le parenchyme pulmonaire est normalement aéré, sans foyer de condensation, nodule, masse, ni signe de fibrose ou de dilatation des bronches.</p><p>Les voies aériennes principales, incluant la trachée et les bronches souches, sont de calibre et de morphologie normaux, sans sténose ni compression extrinsèque.</p><p>Le médiastin est de taille normale et de contours réguliers, sans masse, adénopathie significative ou épanchement.</p><p>Le cœur et les gros vaisseaux (aorte thoracique ascendante, crosse aortique, aorte thoracique descendante, tronc de l''artère pulmonaire et ses branches principales, veines caves) sont de taille et de morphologie normales, sans dilatation anévrismale, dissection ou thrombus.</p><p>Les espaces pleuraux sont libres, sans épanchement ni pneumothorax.</p><p>La paroi thoracique osseuse (côtes, sternum, vertèbres dorsales) est intacte, sans lésion destructrice ni fracture. Les tissus mous de la paroi thoracique sont d''aspect habituel.</p><p>Les coupoles diaphragmatiques sont de contour et de position normaux.</p><p>Les hiles pulmonaires sont non élargis et de morphologie habituelle, sans adénopathie suspecte.</p><p><strong>CONCLUSION :</strong></p><p>Examen tomodensitométrique du thorax sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'TDM Abdomino-Pelvienne Femme', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Tomodensitométrie abdomino-pelvienne réalisée avec administration de produit de contraste intraveineux. Des reconstructions multiplanaires ont été générées.</p><p><strong>RÉSULTATS :</strong></p><p>Foie de taille, morphologie et densité normales, sans lésion focale ni dilatation des voies biliaires intra- ou extrahépatiques.</p><p>Vésicule biliaire non distendue, sans calcul visible et sans épaississement pariétal.</p><p>Rate de taille et d''homogénéité normales, sans lésion focale.</p><p>Pancréas de taille, contours et densité normaux, sans dilatation du canal pancréatique principal ni lésion focale.</p><p>Glandes surrénales de taille et morphologie normales, sans nodule.</p><p>Reins de taille, morphologie et position normales, avec bonne excrétion du contraste, sans calcul, masse ni dilatation des cavités pyélocalicielles.</p><p>Tube digestif (estomac, intestin grêle, côlon) sans dilatation, épaississement pariétal, ou signes d''inflammation. L''appendice est de calibre normal et non inflammatoire.</p><p>Vessie urinaire de paroi fine, bien distendue par l''urine, sans lésion intraluminale.</p><p>Utérus de taille et morphologie normales pour l''âge de la patiente, avec une zone jonctionnelle utérine et un endomètre d''aspect normal.</p><p>Ovaires bilatéraux de taille et morphologie normales pour l''âge de la patiente, sans lésion kystique complexe significative ni masse. De petits follicules simples sont notés.</p><p>Les trompes de Fallope ne sont pas visibles, ce qui est normal.</p><p>Vagin d''aspect normal, sans épaississement ni collection anormale.</p><p>Absence d''adénopathies significatives abdominales ou pelviennes.</p><p>Vaisseaux abdominaux et pelviens perméables, de calibre normal, sans signe de sténose ou d''anévrisme.</p><p>Absence de liquide libre ou de gaz anormal dans les cavités abdominale et pelvienne.</p><p>Les bases pulmonaires sont claires, sans nodule ni épanchement pleural.</p><p>Les structures osseuses visualisées (colonne vertébrale, pelvis) sont d''aspect normal pour l''âge, sans lésion osseuse agressive.</p><p>Les plans graisseux et les tissus mous sont d''aspect normal, sans masse ni collection.</p><p><strong>CONCLUSION :</strong> Examen TDM abdomino-pelvienne sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'TDM Abdomino-Pelvienne Homme', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Réalisation d''un examen tomodensitométrique abdomino-pelvien, sans/avec administration de produit de contraste iodé par voie intraveineuse.</p><p><strong>RÉSULTATS :</strong></p><p>Foie : De taille et de morphologie normales. Contours lisses et homogènes, sans lésion focale ni dilatation des voies biliaires intra-hépatiques. Les structures vasculaires hépatiques sont perméables.</p><p>Vésicule biliaire : Non distendue, à paroi fine, sans calcul ni masse.</p><p>Rate : De taille normale et d''aspect homogène. Contour lisse, sans lésion focale.</p><p>Pancréas : De taille et de morphologie normales. Aspect homogène, sans dilatation canalaire ni lésion focale.</p><p>Glandes surrénales : De taille, de forme et de position normales. Homogènes, sans nodule ni masse.</p><p>Reins : De taille et de morphologie normales, symétriques. Excrétion bilatérale et synchrone du produit de contraste, sans hydronéphrose, lithiase ou masse. Les vaisseaux rénaux sont perméables.</p><p>Appareil digestif : Les anses grêles et coliques sont de calibre normal, à paroi fine et régulière, sans signe d''obstruction, d''épaississement pariétal ou de masse. L''appendice est de calibre normal.</p><p>Vaisseaux principaux : L''aorte et la veine cave inférieure sont de calibre normal et perméables, sans signe d''anévrisme, de dissection ou d''athérosclérose significative.</p><p>Péritoine et mésentère : Sans épanchement liquidien, ni épaississement, ni infiltration graisseuse anormale. Absence de masse ou de lymphadénopathie significative.</p><p>Vessie : À paroi fine et régulière, sans calcul ni masse endoluminale.</p><p>Prostate : De taille normale pour l''âge, d''aspect homogène, sans lésion focale.</p><p>Vésicules séminales : De taille normale et symétriques.</p><p>Structures osseuses (visualisées) : Sans lésion lytique ou blstique évidente, ni fracture. Densité osseuse normale.</p><p>Paroi abdominale et muscles : D''épaisseur normale, sans hernie, collection ou masse.</p><p><strong>CONCLUSION :</strong></p><p>Examen TDM abdomino-pelvien sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'TDM Cérébrale', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Tomodensitométrie cérébrale sans/avec injection intraveineuse de produit de contraste, réalisée selon les protocoles standards.</p><p><strong>RÉSULTATS :</strong></p><p>Le parenchyme cérébral présente une densité et une différenciation substance grise/substance blanche normales, sans signe de lésion focale ou de processus expansif.</p><p>Les gyri et sulci ont un aspect et une distribution normaux, sans effacement des sillons corticaux.</p><p>Le système ventriculaire (ventricules latéraux, troisième et quatrième ventricules) est de taille normale et symétrique, sans dilatation ni déviation de la ligne médiane.</p><p>Les citernes de la base sont perméables et de taille normale.</p><p>Les structures de la fosse postérieure, incluant le tronc cérébral et le cervelet, sont de morphologie et de densité normales, sans anomalie focale.</p><p>Les ganglions de la base et les thalami sont symétriques et de densité normale.</p><p>La faux du cerveau et le tentorium ont un aspect normal, sans déviation.</p><p>Les structures osseuses du crâne sont intactes, sans fracture ou lésion osseuse décelable.</p><p>Les sinus paranasaux et les cellules mastoïdiennes sont normalement aérés et sans signe d''opacification.</p><p>Il n''y a pas d''hémorragie intracrânienne ou de collection liquidienne anormale intra- ou extra-axiale.</p><p><strong>CONCLUSION :</strong></p><p>Examen tomodensitométrique cérébral sans particularité significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'TDM des Sinus', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Réalisation d''un examen tomodensitométrique des sinus en coupes axiales et coronales, avec reconstructions multiplanaires, en fenêtres osseuse et parenchymateuse. L''acquisition a été effectuée sans injection de produit de contraste iodé.</p><p><strong>RÉSULTATS :</strong></p><p>Les sinus frontaux sont normalement pneumatisés et ne contiennent pas de matériel pathologique.</p><p>Les sinus maxillaires sont normalement pneumatisés, sans niveau hydro-aérique ni épaississement muqueux.</p><p>Les cellules ethmoïdales antérieures et postérieures sont normalement pneumatisées et ne présentent pas d''opacification.</p><p>Les sinus sphénoïdaux sont normalement pneumatisés et ne contiennent pas d''anomalie.</p><p>Le septum nasal est en position médiane, sans déviation significative.</p><p>Les cornets nasaux inférieurs, moyens et supérieurs sont de taille normale, sans hypertrophie pathologique.</p><p>Le complexe ostioméatal est perméable bilatéralement, assurant un drainage sinusal adéquat.</p><p>Les parois osseuses des sinus sont intactes et de morphologie normale.</p><p>Les muqueuses sinusiennes sont d''épaisseur normale et fines.</p><p>Les structures osseuses et les tissus mous adjacents visualisés, notamment les orbites et les structures intracrâniennes inférieures, sont sans particularité notable.</p><p><strong>CONCLUSION :</strong></p><p>Examen tomodensitométrique des sinus sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'TDM', 'Angio-TDM des troncs supra-aortiques', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Angio-TDM des troncs supra-aortiques, avec injection de produit de contraste iodé et reconstructions multiplanaires (MPR) et en volume rendering (VR).</p><p><strong>RÉSULTATS :</strong></p><p>L''arc aortique est de position normale (gauche) et présente une anatomie et un trajet habituels.</p><p>Le tronc brachiocéphalique (artère innominée) a une origine, un calibre et un trajet normaux, se bifurquant en artère carotide commune droite et artère subclavière droite.</p><p>Les artères carotides communes droite et gauche présentent un calibre régulier, des parois lisses et un lumen entièrement perméable, sans sténose significative ni occlusion.</p><p>La bifurcation carotidienne (en carotide interne et externe) est de niveau habituel des deux côtés, sans plaque athéromateuse significative ou irrégularité pariétale.</p><p>Les artères carotides internes droite et gauche sont perméables, de calibre normal, sans signe de dissection, anévrisme ou sténose significative.</p><p>Les artères carotides externes droite et gauche sont perméables, avec un calibre et des branches anatomiquement normaux.</p><p>Les artères subclavières droite et gauche présentent un trajet et un calibre normaux, sans sténose, occlusion ou anomalie de leur origine ou de leur cours.</p><p>Les artères vertébrales droite et gauche naissent de façon typique des artères subclavières ipsilatérales, ont un trajet normal et un calibre régulier.</p><p>L''ensemble des lumens vasculaires des troncs supra-aortiques est opacifié de manière homogène et adéquate par le produit de contraste.</p><p>Les tissus mous cervicaux adjacents sont sans particularité notable.</p><p><strong>CONCLUSION :</strong> Examen Angio-TDM des troncs supra-aortiques normal.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie Thoracique', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong></p><p>Radiographie thoracique de face et de profil. Cliché réalisé en inspiration profonde, de bonne qualité technique, symétrique et bien centré.</p><p><strong>RÉSULTATS :</strong></p><p>Les champs pulmonaires sont d''aspect normalement aéré, sans foyer de condensation, ni opacité nodulaire ou masse. La vascularisation pulmonaire est harmonieuse, s''amincissant progressivement du centre à la périphérie.</p><p>Les hiles pulmonaires sont de taille et de densité normales, sans masse ou adénopathie visible.</p><p>La plèvre est fine, sans signe d''épanchement pleural ou de pneumothorax. Les culs-de-sac costo-diaphragmatiques sont libres et nets.</p><p>Les coupoles diaphragmatiques sont de contour régulier et bien définies, avec l''hémidiaphragme droit situé à un niveau physiologique par rapport au gauche.</p><p>Le médiastin est de taille normale, sans élargissement. La trachée est en position médiane et les bronches souches sont perméables.</p><p>La silhouette cardiaque est de taille et de morphologie normales, sans cardiomégalie. Les arcs vasculaires sont conformes.</p><p>Les gros vaisseaux médiastinaux et hilaires sont de calibre normal. Le bouton aortique est sans particularité.</p><p>Le cadre osseux thoracique (côtes, clavicules, omoplates, rachis dorsal) présente un aspect normal, sans lésion osseuse destructrice ou condensante visible.</p><p>Les tissus mous thoraciques et extra-thoraciques sont sans anomalie notable.</p><p><strong>CONCLUSION :</strong></p><p>Examen radiographique du thorax sans anomalie décelable.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'ASP (Abdomen Sans Préparation)', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographie de l''abdomen sans préparation (ASP) en projection antéro-postérieure (AP) en décubitus dorsal.</p><p><strong>RÉSULTATS :</strong></p><p>La distribution des gaz intestinaux est normale, avec la présence habituelle de gaz dans l''estomac et le côlon. Les anses de l''intestin grêle ne sont pas ou peu visibles et ne présentent pas de dilatation anormale.</p><p>Les contours rénaux sont visibles, de taille et de forme normales pour l''âge du patient. Le rein droit est légèrement plus bas que le gauche.</p><p>Les ombres des muscles psoas sont symétriques et bien définies bilatéralement.</p><p>Le foie apparaît comme une densité homogène dans le quadrant supérieur droit.</p><p>La rate peut être visualisée comme une densité homogène dans le quadrant supérieur gauche.</p><p>Aucune calcification anormale n''est identifiée. Les calcifications physiologiques telles que les phlébolithes pelviens ou les calcifications vasculaires bénignes sont notées si présentes et jugées non significatives.</p><p>Les structures osseuses visualisées (vertèbres lombaires, sacrum, pelvis, articulations coxo-fémorales et côtes inférieures) sont d''aspect normal, sans lésion focale ni fracture apparente.</p><p>Absence de signe radiologique de pneumopéritoine ou d''autre gaz extraluminal.</p><p><strong>CONCLUSION :</strong> Examen de l''abdomen sans préparation normal.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie du Bassin', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Réalisation de clichés radiographiques du bassin de face, incidences complémentaires si nécessaire. </p><p><strong>RÉSULTATS :</strong></p><p>Les structures osseuses du bassin (iliaques, ischia, pubis, sacrum et coccyx) présentent une morphologie et une minéralisation osseuse normales. Les contours corticaux sont réguliers et continus.</p><p>Les articulations sacro-iliaques sont d''aspect normal, avec des interlignes articulaires réguliers et une absence de signes de sclérose, d''érosion ou d''ankylose. Elles sont symétriques.</p><p>La symphyse pubienne présente un interligne articulaire d''épaisseur normale et régulière, sans signe de disjonction, d''irrégularité des surfaces ou de sclérose.</p><p>Les articulations coxo-fémorales sont congruentes. Les interlignes articulaires sont conservés et symétriques, sans pincement articulaire ou ostéophytes.</p><p>Les têtes fémorales sont sphériques et bien centrées dans les cavités cotyloïdes. Les cols fémoraux et les trochanters (grand et petit) sont de morphologie normale.</p><p>Les trous obturateurs sont symétriques.</p><p>L''ensemble des lignes corticales des os pelviens est continu et sans interruption, témoignant de l''intégrité osseuse.</p><p>Aucune lésion osseuse focale (fracture, lyse, condensation) n''est identifiée.</p><p><strong>CONCLUSION :</strong> Examen radiographique du bassin sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie du Rachis Cervical', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographies du rachis cervical de face, de profil et bouche ouverte, réalisées selon les incidences standard.</p><p><strong>RÉSULTATS :</strong></p><p>Alignement vertébral : Les lignes vertébrales antérieure, postérieure (ligne de George), spinolaminaire et des épineuses sont continues et suivent une courbure lordotique physiologique, sans décalage ni angulation anormale.</p><p>Corps vertébraux : Les corps vertébraux cervicaux (C1 à C7) sont de hauteur et de densité normales, sans évidence de lésion lytique, blastique ou de tassement.</p><p>Espaces intervertébraux : Les espaces discaux intervertébraux sont de hauteur préservée et parallèles sur tous les niveaux explorés.</p><p>Apophyse odontoïde (Dens) : L''apophyse odontoïde est normally positionnée par rapport à l''arc antérieur de C1, sans signe de fracture ou de déplacement.</p><p>Intervalle atlantodentaire (IAD) : L''espace entre l''arc antérieur de C1 et l''apophyse odontoïde de C2 est dans les limites normales (inférieur à 3 mm chez l''adulte).</p><p>Articulations interapophysaires postérieures (facettes) : Les interlignes articulaires sont bien alignés, sans subluxation ni pincement anormal.</p><p>Apophyses épineuses : Les apophyses épineuses sont alignées et régulièrement espacées.</p><p>Tissus mous prévertébraux : Les tissus mous prévertébraux sont d''épaisseur normale, sans épaississement significatif.</p><p>Jonction craniocervicale : Les articulations entre l''occiput, C1 (atlas) et C2 (axis) apparaissent normales.</p><p><strong>CONCLUSION :</strong> Examen du rachis cervical sans particularité significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Épaule', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographies de l''épaule droite/gauche, comprenant l''incidences de face et de profil, ont été réalisées selon le protocole standard.</p><p><strong>RÉSULTATS :</strong></p><p>La tête humérale est centrée et bien alignée par rapport à la glène.</p><p>La glène de l''omoplate présente un contour régulier, sans signe d''érosion ou de fracture.</p><p>L''acromion est de morphologie normale, sans irrégularité significative.</p><p>Le processus coracoïde est intact et de taille normale.</p><p>L''extrémité distale de la clavicule est normalement positionnée et de structure osseuse homogène.</p><p>L''articulation gléno-humérale présente un interligne articulaire conservé et régulier.</p><p>L''articulation acromio-claviculaire est alignée, sans élargissement ni signe d''arthrose.</p><p>La minéralisation osseuse est normale pour l''âge, sans lésion focale lytique ou blastique suspecte.</p><p>Les contours corticaux des structures osseuses sont réguliers, sans signe de fracture ou de remaniement périosté.</p><p>Les parties molles environnantes sont sans particularité notable, sans calcification pathologique.</p><p><strong>CONCLUSION :</strong> Examen radiographique de l''épaule droite/gauche sans anomalie notable.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie du Poignet', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographies du poignet droit/gauche, incluant des vues de face (PA), de profil strict, obtenues sans difficulté technique.</p><p><strong>RÉSULTATS :</strong></p><p>Alignement Général : Les axes longitudinaux du radius, du semi-lunaire et du grand os sont bien alignés. Les trois arcs carpiens (arcs de Gilula) sont lisses et continus.</p><p>Radius et Ulna : Les corticales osseuses du radius et de l''ulna distaux sont intactes et de morphologie normale. L''inclinaison radiale est conservée (angle normal entre 15 et 25 degrés). L''inclinaison palmaire (volar tilt) du radius est physiologique (angle normal entre 10 et 25 degrés). La hauteur radiale est dans les limites normales (environ 9.9 à 17.3 mm). La variance ulnaire est neutre ou légèrement négative (normale autour de 1-2 mm).</p><p>Os du Carpe : Les huit os du carpe (scaphoïde, semi-lunaire, pyramidal, pisiforme, trapèze, trapézoïde, grand os, hamatum) présentent une structure osseuse et des corticales intactes.</p><p>Intervalles Articulaires : Les interlignes articulaires radio-carpien, médio-carpien et carpo-métacarpiens sont de largeur régulière et conservés (généralement 1-2 mm). Aucune évidence de pincement ou d''élargissement anormal des interlignes.</p><p>Tissus Mous : Les tissus mous périarticulaires sont sans anomalie notable. Les plans graisseux sont visualisés et non déplacés.</p><p><strong>CONCLUSION :</strong></p><p>Examen du poignet sans anomalie radiologique significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie de la Cheville', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographies de la cheville droite/gauche, réalisées en incidences de face et de profil. Clichés de bonne qualité technique, exploitables.</p><p><strong>RÉSULTATS :</strong></p><p>L''alignement osseux de la cheville est conservé.</p><p>Les contours des malléoles tibiale médiale et fibulaire latérale sont réguliers, avec une corticale intacte et sans lésion osseuse décelable.</p><p>Le pilon tibial présente une structure osseuse et une corticale d''aspect normal.</p><p>Le talus (astragale) a une morphologie et une densité osseuse conservées, sans signe de fracture ou d''anomalie.</p><p>Le calcanéum et les autres os du tarse (naviculaire, cuboïde, cunéiformes) ont une intégrité osseuse et corticale maintenues.</p><p>La base du 5ème métatarsien est intègre, sans fracture ni avulsion.</p><p>L''interligne articulaire tibio-talien (mortaiser) est conservé, régulier et symétrique, sans pincement ni élargissement significatif.</p><p>L''articulation tibio-fibulaire distale (syndesmose) est anatomiquement alignée, sans signe de diastasis.</p><p>L''interligne sous-talien et les articulations du médio-pied sont d''aspect conservé.</p><p>Les parties molles périarticulaires sont sans œdème notable, épaississement ou calcifications pathologiques.</p><p><strong>CONCLUSION :</strong> Examen radiographique de la cheville droite/gauche sans anomalie significative décelable.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie du Pied', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Réalisation de radiographies standard du pied droit/gauche, incluant les incidences de face (dorso-plantaire) et de profil.</p><p><strong>RÉSULTATS :</strong></p><p>L''alignement des structures osseuses du pied est normal, sans évidence de subluxation ou de déformation.</p><p>Les os du tarse (talus, calcanéum, naviculaire, cuboïde, cunéiformes) présentent une morphologie et une densité osseuse normales, sans lésion focale ni signe de fracture.</p><p>Les métatarsiens sont de longueur et d''alignement normaux, avec des corticales intactes et un aspect trabéculaire préservé.</p><p>Les phalanges sont intactes et bien alignées, sans déformation ou fracture.</p><p>Les interlignes articulaires (tibio-talienne, sous-talienne, médiotarsiennes - Chopart, tarso-métatarsiennes - Lisfranc, métatarso-phalangiennes et interphalangiennes) sont d''épaisseur normale et bien conservés, sans signe d''arthrose ou d''épanchement significatif.</p><p>Les angles articulaires et les axes de charge, notamment l''angle de Böhler du calcanéum et l''angle de l''hallux valgus, sont dans les limites de la normale.</p><p>La densité osseuse globale est conservée, sans signe de déminéralisation diffuse ou localisée.</p><p>Les parties molles environnantes sont d''épaisseur normale, sans œdème significatif, calcification anormale ou corps étranger radio-opaque visible.</p><p><strong>CONCLUSION :</strong> Examen radiographique du pied droit/gauche sans anomalie significative.</p>');
INSERT INTO templates (user_id, modality, name, content) VALUES (NULL, 'Radio', 'Radiographie de la Main', '<p><strong>INDICATION :</strong></p><p><strong>TECHNIQUE :</strong> Radiographie de la main droite/gauche, réalisée en incidences de face, oblique et profil.</p><p><strong>RÉSULTATS :</strong></p><p>L''alignement des structures osseuses et articulaires est normal.</p><p>Les phalanges proximales, moyennes (sauf le pouce qui en a deux) et distales sont de morphologie et de structure osseuse normales. Aucune fracture ou lésion n''est identifiée.</p><p>Les cinq métacarpiens présentent une densité osseuse et une intégrité corticale normales.</p><p>Les os du carpe (scaphoïde, lunatum, triquétrum, pisiforme, trapèze, trapézoïde, capitatum, hamatum) sont de taille, forme et position normales.</p><p>Les interlignes articulaires interphalangiens (proximaux et distaux), métacarpo-phalangiens et carpo-métacarpiens sont de largeur conservée et sans pincement anormal.</p><p>L''articulation radio-carpienne et l''articulation radio-ulnaire distale sont congruentes, avec des espaces articulaires d''aspect normal.</p><p>La corticale osseuse est régulière et les travées osseuses sont de densité normale.</p><p>Absence de lésion osseuse focale, de signe d''arthrose significative ou de processus infectieux visible.</p><p>Les tissus mous adjacents ne présentent pas de tuméfaction significative ou de corps étranger radio-opaque.</p><p><strong>CONCLUSION :</strong></p><p>Examen radiographique de la main droite/gauche sans anomalie significative.</p>');
